'use client';

import * as React from 'react';
import { supabaseClient } from '@/lib/supabaseClient';
import { useDashboardAuth } from '@/lib/dashboard-auth-context';
import { Button } from '@/components/ui/button';
import { Loader2, CheckCircle2, AlertCircle } from 'lucide-react';

type Order = {
  id: string;
  invoice_id: string;
  customer_name: string | null;
  payment_method: string | null;
  payment_status: 'Confirmed' | 'Check';
  total_amount: number;
  delivery_fee: number | null;
  courier_name: string | null;
  created_at: string;
  sale_type: 'Shop' | 'Delivery';
};

export default function DeliverySalesLogPage() {
  const { role } = useDashboardAuth();
  const [orders, setOrders] = React.useState<Order[]>([]);
  const [loading, setLoading] = React.useState(true);
  const [updatingId, setUpdatingId] = React.useState<string | null>(null);

  const fetchOrders = React.useCallback(async () => {
    setLoading(true);
    const { data, error } = await supabaseClient
      .from('orders')
      .select('*')
      .eq('sale_type', 'Delivery')
      .order('created_at', { ascending: false });

    if (error) {
      console.error('Error fetching orders:', error);
    } else {
      setOrders(data || []);
    }
    setLoading(false);
  }, []);

  React.useEffect(() => {
    if (role === 'admin') {
      fetchOrders();
    }
  }, [role, fetchOrders]);

  const togglePaymentStatus = async (orderId: string, currentStatus: string) => {
    setUpdatingId(orderId);
    const newStatus = currentStatus === 'Confirmed' ? 'Check' : 'Confirmed';
    try {
      const res = await fetch(`/api/orders/${orderId}/status`, {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ status: newStatus }),
      });
      if (res.ok) {
        setOrders((prev) =>
          prev.map((o) => (o.id === orderId ? { ...o, payment_status: newStatus as any } : o))
        );
      }
    } catch (err) {
      console.error('Failed to update status:', err);
    } finally {
      setUpdatingId(null);
    }
  };

  const dailySummary = React.useMemo(() => {
    const summary: Record<string, { methods: Record<string, number>; fees: number }> = {};
    orders.forEach((order) => {
      const dateKey = new Date(order.created_at).toLocaleDateString();
      const method = order.payment_method || 'Unknown';
      const deliveryFee = Number(order.delivery_fee || 0);
      const collected = (order.total_amount || 0) + deliveryFee;
      if (!summary[dateKey]) {
        summary[dateKey] = { methods: {}, fees: 0 };
      }
      summary[dateKey].methods[method] = (summary[dateKey].methods[method] || 0) + collected;
      summary[dateKey].fees += deliveryFee;
    });
    return summary;
  }, [orders]);

  if (role !== 'admin') {
    return (
      <div className="space-y-4">
        <h1 className="text-xl font-semibold tracking-tight md:text-2xl">
          Delivery Sales Log
        </h1>
        <p className="text-sm text-muted-foreground">
          Access restricted. Sales reports are available to admins only.
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-semibold tracking-tight md:text-2xl">
          Delivery Sales Log
        </h1>
        <Button variant="outline" size="sm" onClick={fetchOrders} disabled={loading}>
          {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : 'Refresh'}
        </Button>
      </div>

      <div className="rounded-lg border border-border bg-card p-4 space-y-4">
        <div className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">
          Daily Summary
        </div>
        {Object.keys(dailySummary).length === 0 && (
          <div className="text-xs text-muted-foreground">No summary available.</div>
        )}
        {Object.entries(dailySummary).map(([date, summary]) => (
          <div key={date} className="space-y-2">
            <div className="text-sm font-semibold">{date}</div>
            <div className="flex flex-wrap gap-2">
              {Object.entries(summary.methods).map(([method, total]) => (
                <span key={method} className="rounded-full bg-secondary px-2 py-1 text-[10px] font-semibold">
                  {method}: {total.toLocaleString()} Ks
                </span>
              ))}
            </div>
            <div className="text-[11px] text-muted-foreground">
              Total Delivery Fees: {summary.fees.toLocaleString()} Ks
            </div>
          </div>
        ))}
      </div>

      {loading && orders.length === 0 ? (
        <div className="flex justify-center py-10">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      ) : (
        <div className="rounded-lg border border-border bg-card overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-sm text-left">
              <thead className="bg-secondary/50 text-xs font-semibold uppercase tracking-wider text-muted-foreground border-b border-border">
                <tr>
                  <th className="px-4 py-3">Date</th>
                  <th className="px-4 py-3">Invoice</th>
                  <th className="px-4 py-3">Customer</th>
                  <th className="px-4 py-3">Courier</th>
                  <th className="px-4 py-3 text-right">Delivery Fee</th>
                  <th className="px-4 py-3">Payment Method</th>
                  <th className="px-4 py-3 text-right">Collected</th>
                  <th className="px-4 py-3 text-center">Payment Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {orders.map((order) => {
                  const date = new Date(order.created_at).toLocaleDateString();
                  const isConfirmed = order.payment_status === 'Confirmed';
                  const deliveryFee = Number(order.delivery_fee || 0);
                  const collected = (order.total_amount || 0) + deliveryFee;

                  return (
                    <tr key={order.id} className="hover:bg-secondary/20 transition-colors">
                      <td className="px-4 py-4 whitespace-nowrap text-muted-foreground">
                        {date}
                      </td>
                      <td className="px-4 py-4 font-mono font-medium">
                        {order.invoice_id}
                      </td>
                      <td className="px-4 py-4">
                        {order.customer_name || '—'}
                      </td>
                      <td className="px-4 py-4">
                        {order.courier_name || '—'}
                      </td>
                      <td className="px-4 py-4 text-right font-semibold">
                        {deliveryFee.toLocaleString()} Ks
                      </td>
                      <td className="px-4 py-4">
                        {order.payment_method || '—'}
                      </td>
                      <td className="px-4 py-4 text-right font-semibold">
                        {collected.toLocaleString()} Ks
                      </td>
                      <td className="px-4 py-4 text-center">
                        <Button
                          variant={isConfirmed ? 'ghost' : 'outline'}
                          size="sm"
                          className={`h-8 gap-1.5 ${isConfirmed ? 'text-emerald-400 hover:text-emerald-300' : 'text-amber-400 hover:text-amber-300'}`}
                          onClick={() => togglePaymentStatus(order.id, order.payment_status)}
                          disabled={updatingId === order.id}
                        >
                          {updatingId === order.id ? (
                            <Loader2 className="h-3 w-3 animate-spin" />
                          ) : isConfirmed ? (
                            <CheckCircle2 className="h-4 w-4" />
                          ) : (
                            <AlertCircle className="h-4 w-4" />
                          )}
                          {order.payment_status}
                        </Button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          {orders.length === 0 && (
            <div className="py-20 text-center text-muted-foreground">
              No delivery records found.
            </div>
          )}
        </div>
      )}
    </div>
  );
}
